import models from '../models'
import { AdminService } from '../services/admin'
import { Service } from '../services/base'

const DataLoadMixin = {
  props: {
    model: {
      type: String,
      required: true,
      default: 'Test'
    },
    serviceType: {
      type: String,
      required: false,
      default: 'base'
    }
  },
  data() {
    return {
      icon: false,
    }
  },
  computed: {
    modelObj() {
      return new models[this.model]()
    }
  },
  async created() {
    console.log(this.model)
    if (this.serviceType.toLowerCase() === 'user') {
      this.service = new AdminService()
    } else {
      this.service = new Service(this.model)
    }
  }
}

export default DataLoadMixin
